import React from "react";

const Navbar = () => {

  const handleScroll = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav className="navbar">
      <div className="navdiv">
        <div className="logo">
          <a onClick={() => handleScroll('home')} style={{ cursor: 'pointer' }}>Sindhuja Kannuri</a>
        </div>

        <ul>
          <li><a onClick={() => handleScroll('about')} style={{ cursor: 'pointer' }}>About</a></li>
          <li><a onClick={() => handleScroll('experience')} style={{ cursor: 'pointer' }}>Experience</a></li>
          <li><a onClick={() => handleScroll('projects')} style={{ cursor: 'pointer' }}>Projects</a></li>
            <li><a onClick={() => handleScroll('skills')} style={{ cursor: 'pointer' }}>Skills</a></li>
          <li><a onClick={() => handleScroll('contact')} style={{ cursor: 'pointer' }}>Contact</a></li>
          <li>
            <button onClick={() => handleScroll('contact')}>
              Get In Touch
            </button>
          </li>
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
